class Solution:
    def backspaceCompare(self, s: str, t: str) -> bool:
        def process(s):
            res = []
            for c in s:
                if c != '#':
                    res.append(c)
                elif res:
                    res.pop()
            return ''.join(res)
        return process(s) == process(t)
